+  if (byNormalizedTitle) return byNormalizedTitle;
+
+  const byContains = cards.find((c) => normalizeOperatorTitle(`${c.symbol} ${c.title}`) === normalizedQuery);
+  if (byContains) return byContains;
+
+  return null;
